class Solution {
    public String solve(String[] words, int[] weights) {
        StringBuilder result = new StringBuilder();
        for (String word : words) {
            int weightSum = 0;
            for (char c : word.toCharArray()) {
                weightSum += weights[c - 'a'];
            }
            int mappedWeight = weightSum % 26;
            result.append((char) ('a' + mappedWeight));
        }
        return result.toString();
    }
}

def map_words_to_string(words, weights):
    result = []
    for word in words:
        weight = sum(weights[ord(c) - ord('a')] for c in word)
        mapped_char = chr(ord('a') + (26 - (weight % 26) - 1))
        result.append(mapped_char)
    return ''.join(result)

