public class Solution {
    public String mapWeights(String[] words, int[] weights) {
        StringBuilder result = new StringBuilder();
        for (String word : words) {
            int weight = 0;
            for (char c : word.toCharArray()) {
                weight += weights[c - 'a'];
            }
            result.append((char) ('a' + (25 - weight % 26)));
        }
        return result.toString();
    }
}

def map_words_to_characters(words, weights):
    result = []
    for word in words:
        total_weight = 0
        for ch in word:
            total_weight += weights[ord(ch) - ord('a')]
        modulo_val = total_weight % 26
        mapped_char = chr(ord('z') - modulo_val)
        result.append(mapped_char)
    return ''.join(result)

class Solution {
    public String calculateMapping(String[] words, int[] weights) {
        StringBuilder result = new StringBuilder();
        for (String word : words) {
            int weight = 0;
            for (char c : word.toCharArray()) {
                weight += weights[c - 'a'];
            }
            int mod = weight % 26;
            char mapped = (char) ('z' - mod);
            result.append(mapped);
        }
        return result.toString();
    }
}
